+      channel: "telegram",
+      to: "12345",
+      threadId: "77",
+    });
+    expect(job?.payload).toMatchObject({
+      kind: "agentTurn",
+      message: "say hi",
+      model: "openai/gpt-5.4",
+    });
+  });
+
+  it("normalizes payload provider alias into channel", () => {
+    const jobs = [
+      {
+        id: "legacy-provider",
